mapper.select:
/* Risk01Mapper.selectRiskTypeList */ SELECT A.CMPNY_CD AS cmpnyCd , A.RISK_TYPE_CD AS riskTypeCd , A.RISK_TYPE_NM AS riskTypeNm , A.SITE_CD AS siteCd , A.PROCESS_CD AS processCd , A.USE_YN AS useYn , A.RISK_TYPE_DESC AS riskTypeDesc FROM TB_RISK_TYPE A WHERE 1=1 AND ( A.SITE_CD IS NULL OR A.SITE_CD = ''
OR A.SITE_CD = #{param.siteCd}
)
AND A.PROCESS_CD = #{param.processCd}
AND A.RISK_TYPE_NM LIKE CONCAT('%', #{param.riskTypeNm}, '%')
AND A.USE_YN = #{param.useYn}

mapper.update:
	/* Risk01Mapper.mergeRistType */
    INSERT INTO TB_RISK_TYPE (
    	CMPNY_CD
    	, RISK_TYPE_CD
    	, RISK_TYPE_NM
    	, SITE_CD
    	, PROCESS_CD
    	, USE_YN
    	, RISK_TYPE_DESC
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, IFNULL(#{param.riskTypeCd}, FNC_CMM_SEQ_NEXTVAL(#{token.gv_cmpnyCd}, 'RISK_TYPE_CD'))
   		, #{param.riskTypeNm}
   		, #{param.siteCd}
   		, #{param.processCd}
		, #{param.useYn}
		, #{param.riskTypeDesc}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    RISK_TYPE_NM	= VALUES(RISK_TYPE_NM)
	    , USE_YN		= IFNULL(#{param.useYn}, 'Y')
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

mapper.select:
 /* Risk01Mapper.selectRiskHazardCnt */
 SELECT COUNT(*)
	FROM TB_RISK_HAZARD
	WHERE 1=1
	  AND CMPNY_CD = #{param.cmpnyCd}
	  AND RISK_TYPE_CD = #{param.riskTypeCd}

mapper.delete:
/* Risk01Mapper.deleteRistType */
DELETE FROM TB_RISK_TYPE
WHERE CMPNY_CD = #{param.cmpnyCd}
  AND RISK_TYPE_CD = #{param.riskTypeCd}

  	AND SITE_CD = #{param.siteCd}

  AND PROCESS_CD = #{param.processCd}

mapper.select:
/* Risk01Mapper.selectRiskHazardList */ SELECT '' AS chk , CMPNY_CD AS cmpnyCd , RISK_TYPE_CD AS riskTypeCd , HAZARD_CD AS hazardCd , HAZARD_NM AS hazardNm , SITE_CD AS siteCd , HAZARD_DESC AS hazardDesc FROM TB_RISK_SITE_HAZARD WHERE 1=1 AND CMPNY_CD = #{token.gv_cmpnyCd} AND RISK_TYPE_CD = #{param.riskTypeCd}
AND HAZARD_NM LIKE CONCAT('%', #{param.hazardNm}, '%')
AND HAZARD_DESC LIKE CONCAT('%', #{param.hazardDesc}, '%')

mapper.update:
	/* Risk01Mapper.mergeRiskHazard */
	INSERT INTO TB_RISK_SITE_HAZARD (
    	CMPNY_CD
    	, RISK_TYPE_CD
    	, HAZARD_CD
    	, HAZARD_NM
    	, SITE_CD
    	, HAZARD_DESC  	
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, #{param.riskTypeCd}
   		, IFNULL(#{param.hazardCd}, FNC_CMM_SEQ_NEXTVAL(#{token.gv_cmpnyCd}, 'HAZARD_CD'))
   		, #{param.hazardNm}
   		, #{param.siteCd}
		, #{param.hazardDesc}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    HAZARD_NM		= VALUES(HAZARD_NM)
	    , HAZARD_DESC	= VALUES(HAZARD_DESC)
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

mapper.delete:
/* Risk01Mapper.deleteRiskHazard */
DELETE FROM TB_RISK_SITE_HAZARD
WHERE CMPNY_CD = #{token.gv_cmpnyCd}
  AND RISK_TYPE_CD = #{param.riskTypeCd}
  AND HAZARD_CD = #{param.hazardCd}

  	AND SITE_CD = #{param.siteCd}

mapper.select:
/* Baim01Mapper.selectSiteInfoList */ SELECT '' AS CHK , A.SITE_CD , A.SITE_NO , A.SITE_NM , A.CMPNY_CD , A.ADDR_1 , A.ADDR_2 , A.ZIP_CODE , A.STR_DATE , A.END_DATE , A.USE_YN , A.SITE_ADMIN_ID , B.USER_ID AS SITE_ADMIN_NM , A.TEL_NO , A.SITE_DESC FROM TB_SITE A LEFT JOIN TB_USER B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_ADMIN_ID = B.USER_ID ) WHERE 1=1 AND A.CMPNY_CD = #{gv_cmpnyCd}
AND A.SITE_CD = #{siteCd}
AND A.SITE_NO = #{siteNo}
AND A.SITE_NM LIKE CONCAT('%', #{siteNm}, '%')
AND A.USE_YN = #{useYn}
